func executionStatusClass(status string) string {
	switch status {
	case "completed":
		return "text-green-400"
	case "failed", "blocked":
		return "text-red-400"
	case "running", "starting":
		return "text-blue-400"
	default:
		return "text-gray-400"
	}
}

func cliCheckStatusClass(status string) string {
	switch status {
	case "pass":
		return "relay-chip-green"
	case "warn":
		return "relay-chip-yellow"
	case "fail":
		return "relay-chip-red"
	default:
		return "relay-chip-gray"
	}
}

func isExecutionRunning(status string) bool {
	return status == "starting" || status == "running"
}

func parsedResultStatusClass(status string) string {
	switch status {
	case "DONE":
		return "text-green-400"
	case "BLOCKED":
		return "text-red-400"
	default:
		return "text-yellow-400"
	}
}

func cliCheckModelAvailableClass(available string) string {
	switch available {
	case "yes":
		return "text-green-400"
	case "no":
		return "text-red-400"
	default:
		return "text-gray-500"
	}
}

func dryRunDisabledReason(previews RunPreviews) string {
	if previews.OpenCodeAdapterError != "" {
		return "adapter blocked: " + previews.OpenCodeAdapterError
	}
	if previews.OpenCodeCommandPreview == "" {
		return "no command preview; complete earlier steps first"
	}
	return "not available"
}

func startDisabledReason(previews RunPreviews) string {
	if previews.OpenCodeAdapterError != "" {
		return "adapter blocked: " + previews.OpenCodeAdapterError
	}
	if previews.HandoffPreflightStatus == "blocked" {
		return "handoff preflight checks are blocked"
	}
	if previews.OpenCodeCommandPreview == "" {
		return "no command preview; complete earlier steps first"
	}
	return "not available"
}

type relayValidationUIState string

const (
	relayValidationNoResult   relayValidationUIState = "no_result"
	relayValidationNoCommands relayValidationUIState = "no_commands"
	relayValidationReady      relayValidationUIState = "ready"
	relayValidationCompleted  relayValidationUIState = "completed"
)

func validationProgressFinished(previews RunPreviews) bool {
	return previews.HasValidationProgress && (previews.ValidationProgressPreview.Status == "pass" || previews.ValidationProgressPreview.Status == "fail")
}

func relayValidationUIStateFor(hasAgentResult bool, hasValidationCommands bool, hasValidationRun bool) relayValidationUIState {
	if hasValidationRun {
		return relayValidationCompleted
	}
	if !hasAgentResult {
		return relayValidationNoResult
	}
	if !hasValidationCommands {
		return relayValidationNoCommands
	}
	return relayValidationReady
}

func stageEvidenceSymbol(status string) string {
	switch status {
	case "passed":
		return "✓"
	case "failed", "blocked":
		return "✗"
	case "warning":
		return "!"
	case "running":
		return "▶"
	case "ready":
		return "●"
	case "pending":
		return "○"
	case "not-available":
		return "—"
	default:
		return "○"
	}
}

func stageEvidenceTitleClass(status string) string {
	switch status {
	case "passed":
		return "text-green-300"
	case "failed", "blocked":
		return "text-red-300"
	case "warning":
		return "text-yellow-300"
	case "running":
		return "text-blue-300"
	case "ready":
		return "text-indigo-300"
	case "pending":
		return "text-gray-400"
	default:
		return "text-gray-200"
	}
}

